import javax.xml.parsers.*; // Import the required classes/packages (use * for wildcard import *)  
import org.w3c.dom.*;    // Use specific class(es), if necessary, instead of using 'Document'. If multiple are needed use a comma-separated list: Document...  and not just one at a time as in this example with the line that contains it too (as seen below)
import javax.xml.parsers.*;   // Importing parser classes to parse XML documents into DOM tree model of objects, such an instance has been imported for creating instances using document builder factory..  and not required while parsing xml string as there is no need in this case unless we are dealing with a file
import org.xml.sax.*;    // SAX (Simple API for XML) parser classes to read/parse the content of an XML Document; can be used only once at initialization time, then it should not get any new data from DOM tree model  while parsing xml string as there is no need in this case unless we are dealing with a file
import org.xml.sax.helpers.*; // Import SAX helper classes such the InputSource (used to read XML documents), and Read/Write callback method...   for validation, but not required if only processing an input stream or output streams  as there is no need in this case unless we are dealing with a file
import javax.xml.transform.*;    // Importing transformer class java_52500_XMLParser_A03 can convert xml document into another format (like PDF) using the provided classes/objects; and it should be used when you want to create an XML from DOM tree model of objects, or any other transformation scenario  in order not required while parsing a file with JAXP.
import javax.xml.transform.dom.*; // Importing class that can convert xml document into another format (like PDF) using the provided classes/objects; and it should be used when you want to create an XML from DOM tree model of objects, or any other transformation scenario  in order not required while parsing a file with JAXP